18	
19	import java.util.ArrayList;
20	import java.util.Collections;
21	import java.util.List;
22	
23	import org.jspecify.annotations.Nullable;
24	
25	import org.springframework.boot.autoconfigure.AutoConfigurationImportFilter;
26	import org.springframework.boot.autoconfigure.AutoConfigurationMetadata;
27	import org.springframework.boot.autoconfigure.condition.ConditionMessage.Style;
28	import org.springframework.context.annotation.Condition;
29	import org.springframework.context.annotation.ConditionContext;
30	import org.springframework.core.Ordered;
31	import org.springframework.core.annotation.Order;
32	import org.springframework.core.type.AnnotatedTypeMetadata;
33	import org.springframework.util.MultiValueMap;
34	import org.springframework.util.ReflectionUtils;
35	import org.springframework.util.StringUtils;
36	
37	/**
38	 * {@link Condition} and {@link AutoConfigurationImportFilter} that checks for the
39	 * presence or absence of specific classes.
40	 *
41	 * @author Phillip Webb
42	 * @see ConditionalOnClass
43	 * @see ConditionalOnMissingClass
44	 */
45	@Order(Ordered.HIGHEST_PRECEDENCE)
46	class OnClassCondition extends FilteringSpringBootCondition {
47	
48		@Override
49		protected final @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses,
50				AutoConfigurationMetadata autoConfigurationMetadata) {
51			// Split the work and perform half in a background thread if more than one
52			// processor is available. Using a single additional thread seems to offer the
53			// best performance. More threads make things worse.
54			if (autoConfigurationClasses.length > 1 && Runtime.getRuntime().availableProcessors() > 1) {
55				return resolveOutcomesThreaded(autoConfigurationClasses, autoConfigurationMetadata);
56			}
57			else {
58				OutcomesResolver outcomesResolver = new StandardOutcomesResolver(autoConfigurationClasses, 0,
59						autoConfigurationClasses.length, autoConfigurationMetadata, getBeanClassLoader());
60				return outcomesResolver.resolveOutcomes();
61			}
62		}
63	
64		private @Nullable ConditionOutcome[] resolveOutcomesThreaded(@Nullable String[] autoConfigurationClasses,
65				AutoConfigurationMetadata autoConfigurationMetadata) {
66			int split = autoConfigurationClasses.length / 2;
67			OutcomesResolver firstHalfResolver = createOutcomesResolver(autoConfigurationClasses, 0, split,
68					autoConfigurationMetadata);
69			OutcomesResolver secondHalfResolver = new StandardOutcomesResolver(autoConfigurationClasses, split,
70					autoConfigurationClasses.length, autoConfigurationMetadata, getBeanClassLoader());
71			@Nullable ConditionOutcome[] secondHalf = secondHalfResolver.resolveOutcomes();
72			@Nullable ConditionOutcome[] firstHalf = firstHalfResolver.resolveOutcomes();
73			@Nullable ConditionOutcome[] outcomes = new ConditionOutcome[autoConfigurationClasses.length];
74			System.arraycopy(firstHalf, 0, outcomes, 0, firstHalf.length);
75			System.arraycopy(secondHalf, 0, outcomes, split, secondHalf.length);
76			return outcomes;
77		}
78	
79		private OutcomesResolver createOutcomesResolver(@Nullable String[] autoConfigurationClasses, int start, int end,
80				AutoConfigurationMetadata autoConfigurationMetadata) {
81			OutcomesResolver outcomesResolver = new StandardOutcomesResolver(autoConfigurationClasses, start, end,
82					autoConfigurationMetadata, getBeanClassLoader());
83			return new ThreadedOutcomesResolver(outcomesResolver);
84		}
85	
86		@Override
87		public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
88			ClassLoader classLoader = context.getClassLoader();
89			ConditionMessage matchMessage = ConditionMessage.empty();
90			List<String> onClasses = getCandidates(metadata, ConditionalOnClass.class);
91			if (onClasses != null) {
92				List<String> missing = filter(onClasses, ClassNameFilter.MISSING, classLoader);
93				if (!missing.isEmpty()) {
94					return ConditionOutcome.noMatch(ConditionMessage.forCondition(ConditionalOnClass.class)
95						.didNotFind("required class", "required classes")
96						.items(Style.QUOTE, missing));
97				}
98				matchMessage = matchMessage.andCondition(ConditionalOnClass.class)
99					.found("required class", "required classes")
100					.items(Style.QUOTE, filter(onClasses, ClassNameFilter.PRESENT, classLoader));
101			}
102			List<String> onMissingClasses = getCandidates(metadata, ConditionalOnMissingClass.class);
103			if (onMissingClasses != null) {
104				List<String> present = filter(onMissingClasses, ClassNameFilter.PRESENT, classLoader);
105				if (!present.isEmpty()) {
106					return ConditionOutcome.noMatch(ConditionMessage.forCondition(ConditionalOnMissingClass.class)
107						.found("unwanted class", "unwanted classes")
108						.items(Style.QUOTE, present));
109				}
110				matchMessage = matchMessage.andCondition(ConditionalOnMissingClass.class)
111					.didNotFind("unwanted class", "unwanted classes")
112					.items(Style.QUOTE, filter(onMissingClasses, ClassNameFilter.MISSING, classLoader));
113			}
114			return ConditionOutcome.match(matchMessage);
115		}
116	
117		private @Nullable List<String> getCandidates(AnnotatedTypeMetadata metadata, Class<?> annotationType) {
118			MultiValueMap<String, @Nullable Object> attributes = metadata
119				.getAllAnnotationAttributes(annotationType.getName(), true);
120			if (attributes == null) {
121				return null;
122			}
123			List<String> candidates = new ArrayList<>();
124			addAll(candidates, attributes.get("value"));
125			addAll(candidates, attributes.get("name"));
126			return candidates;
127		}
128	
129		private void addAll(List<String> list, @Nullable List<@Nullable Object> itemsToAdd) {
130			if (itemsToAdd != null) {
131				for (Object item : itemsToAdd) {
132					if (item != null) {
133						Collections.addAll(list, (String[]) item);
134					}
135				}
136			}
137		}
138	
139		private interface OutcomesResolver {
140	
141			@Nullable ConditionOutcome[] resolveOutcomes();
142	
143		}
144	
145		private static final class ThreadedOutcomesResolver implements OutcomesResolver {
146	
147			private final Thread thread;
148	
149			private volatile @Nullable ConditionOutcome @Nullable [] outcomes;
150	
151			private volatile @Nullable Throwable failure;
152	
153			private ThreadedOutcomesResolver(OutcomesResolver outcomesResolver) {
154				this.thread = new Thread(() -> {
155					try {
156						this.outcomes = outcomesResolver.resolveOutcomes();
157					}
158					catch (Throwable ex) {
159						this.failure = ex;
160					}
161				});
162				this.thread.start();
163			}
164	
165			@Override
166			public @Nullable ConditionOutcome[] resolveOutcomes() {
167				try {
168					this.thread.join();
169				}
170				catch (InterruptedException ex) {
171					Thread.currentThread().interrupt();
172				}
173				Throwable failure = this.failure;
174				if (failure != null) {
175					ReflectionUtils.rethrowRuntimeException(failure);
176				}
177				@Nullable ConditionOutcome[] outcomes = this.outcomes;
178				return (outcomes != null) ? outcomes : new ConditionOutcome[0];
179			}
180	
181		}
182	
183		private static final class StandardOutcomesResolver implements OutcomesResolver {
184	
185			private final @Nullable String[] autoConfigurationClasses;
186	
187			private final int start;
188	
189			private final int end;
190	
191			private final AutoConfigurationMetadata autoConfigurationMetadata;
192	
193			private final ClassLoader beanClassLoader;
194	
195			private StandardOutcomesResolver(@Nullable String[] autoConfigurationClasses, int start, int end,
196					AutoConfigurationMetadata autoConfigurationMetadata, ClassLoader beanClassLoader) {
197				this.autoConfigurationClasses = autoConfigurationClasses;
198				this.start = start;
199				this.end = end;
200				this.autoConfigurationMetadata = autoConfigurationMetadata;
201				this.beanClassLoader = beanClassLoader;
202			}
203	
204			@Override
205			public @Nullable ConditionOutcome[] resolveOutcomes() {
206				return getOutcomes(this.autoConfigurationClasses, this.start, this.end, this.autoConfigurationMetadata);
207			}
208	
209			private @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses, int start,
210					int end, AutoConfigurationMetadata autoConfigurationMetadata) {
211				@Nullable ConditionOutcome[] outcomes = new ConditionOutcome[end - start];
212				for (int i = start; i < end; i++) {
213					String autoConfigurationClass = autoConfigurationClasses[i];
214					if (autoConfigurationClass != null) {
215						String candidates = autoConfigurationMetadata.get(autoConfigurationClass, "ConditionalOnClass");
216						if (candidates != null) {
217							outcomes[i - start] = getOutcome(candidates);
218						}
219					}
220				}
221				return outcomes;
222			}
223	
224			private @Nullable ConditionOutcome getOutcome(String candidates) {
225				try {
226					if (!candidates.contains(",")) {
227						return getOutcome(candidates, this.beanClassLoader);
228					}
229					for (String candidate : StringUtils.commaDelimitedListToStringArray(candidates)) {
230						ConditionOutcome outcome = getOutcome(candidate, this.beanClassLoader);
231						if (outcome != null) {
232							return outcome;
233						}
234					}
235				}
236				catch (Exception ex) {
237					// We'll get another chance later
238				}
239				return null;
240			}
241	
242			private @Nullable ConditionOutcome getOutcome(String className, ClassLoader classLoader) {
243				if (ClassNameFilter.MISSING.matches(className, classLoader)) {
244					return ConditionOutcome.noMatch(ConditionMessage.forCondition(ConditionalOnClass.class)
245						.didNotFind("required class")
246						.items(Style.QUOTE, className));
247				}
248				return null;
249			}
250	
251		}
252	
253	}
