64	/**
65	 * {@link DeferredImportSelector} to handle {@link EnableAutoConfiguration
66	 * auto-configuration}. This class can also be subclassed if a custom variant of
67	 * {@link EnableAutoConfiguration @EnableAutoConfiguration} is needed.
68	 *
69	 * @author Phillip Webb
70	 * @author Andy Wilkinson
71	 * @author Stephane Nicoll
72	 * @author Madhura Bhave
73	 * @author Moritz Halbritter
74	 * @author Scott Frederick
75	 * @since 1.3.0
76	 * @see EnableAutoConfiguration
77	 */
78	public class AutoConfigurationImportSelector implements DeferredImportSelector, BeanClassLoaderAware,
79			ResourceLoaderAware, BeanFactoryAware, EnvironmentAware, Ordered {
80	
81		static final int ORDER = Ordered.LOWEST_PRECEDENCE - 1;
82	
83		private static final AutoConfigurationEntry EMPTY_ENTRY = new AutoConfigurationEntry();
84	
85		private static final String[] NO_IMPORTS = {};
86	
87		private static final Log logger = LogFactory.getLog(AutoConfigurationImportSelector.class);
88	
89		private static final String PROPERTY_NAME_AUTOCONFIGURE_EXCLUDE = "spring.autoconfigure.exclude";
90	
91		private final Class<?> autoConfigurationAnnotation;
92	
93		@SuppressWarnings("NullAway.Init")
94		private ConfigurableListableBeanFactory beanFactory;
95	
96		@SuppressWarnings("NullAway.Init")
97		private Environment environment;
98	
99		@SuppressWarnings("NullAway.Init")
100		private ClassLoader beanClassLoader;
101	
102		@SuppressWarnings("NullAway.Init")
103		private ResourceLoader resourceLoader;
104	
105		private volatile @Nullable ConfigurationClassFilter configurationClassFilter;
106	
107		private volatile @Nullable AutoConfigurationReplacements autoConfigurationReplacements;
108	
109		public AutoConfigurationImportSelector() {
110			this(null);
111		}
112	
113		AutoConfigurationImportSelector(@Nullable Class<?> autoConfigurationAnnotation) {
114			this.autoConfigurationAnnotation = (autoConfigurationAnnotation != null) ? autoConfigurationAnnotation
115					: AutoConfiguration.class;
116		}
117	
118		@Override
119		public String[] selectImports(AnnotationMetadata annotationMetadata) {
120			if (!isEnabled(annotationMetadata)) {
121				return NO_IMPORTS;
122			}
123			AutoConfigurationEntry autoConfigurationEntry = getAutoConfigurationEntry(annotationMetadata);
124			return StringUtils.toStringArray(autoConfigurationEntry.getConfigurations());
125		}
126	
127		@Override
128		public Predicate<String> getExclusionFilter() {
129			return this::shouldExclude;
130		}
131	
132		private boolean shouldExclude(String configurationClassName) {
133			return getConfigurationClassFilter().filter(Collections.singletonList(configurationClassName)).isEmpty();
134		}
135	
136		/**
137		 * Return the {@link AutoConfigurationEntry} based on the {@link AnnotationMetadata}
138		 * of the importing {@link Configuration @Configuration} class.
139		 * @param annotationMetadata the annotation metadata of the configuration class
140		 * @return the auto-configurations that should be imported
141		 */
142		protected AutoConfigurationEntry getAutoConfigurationEntry(AnnotationMetadata annotationMetadata) {
143			if (!isEnabled(annotationMetadata)) {
144				return EMPTY_ENTRY;
145			}
146			AnnotationAttributes attributes = getAttributes(annotationMetadata);
147			List<String> configurations = getCandidateConfigurations(annotationMetadata, attributes);
148			configurations = removeDuplicates(configurations);
149			Set<String> exclusions = getExclusions(annotationMetadata, attributes);
150			checkExcludedClasses(configurations, exclusions);
151			configurations.removeAll(exclusions);
152			configurations = getConfigurationClassFilter().filter(configurations);
153			fireAutoConfigurationImportEvents(configurations, exclusions);
154			return new AutoConfigurationEntry(configurations, exclusions);
155		}
156	
157		@Override
158		public Class<? extends Group> getImportGroup() {
159			return AutoConfigurationGroup.class;
160		}
161	
162		protected boolean isEnabled(AnnotationMetadata metadata) {
163			if (getClass() == AutoConfigurationImportSelector.class) {
164				return getEnvironment().getProperty(EnableAutoConfiguration.ENABLED_OVERRIDE_PROPERTY, Boolean.class, true);
165			}
166			return true;
167		}
168	
169		/**
170		 * Return the appropriate {@link AnnotationAttributes} from the
171		 * {@link AnnotationMetadata}. By default this method will return attributes for
172		 * {@link #getAnnotationClass()}.
173		 * @param metadata the annotation metadata
174		 * @return annotation attributes
175		 */
176		protected @Nullable AnnotationAttributes getAttributes(AnnotationMetadata metadata) {
177			String name = getAnnotationClass().getName();
178			AnnotationAttributes attributes = AnnotationAttributes.fromMap(metadata.getAnnotationAttributes(name, true));
179			Assert.state(attributes != null, () -> "No auto-configuration attributes found. Is " + metadata.getClassName()
180					+ " annotated with " + ClassUtils.getShortName(name) + "?");
181			return attributes;
182		}
183	
184		/**
185		 * Return the source annotation class used by the selector.
186		 * @return the annotation class
187		 */
188		protected Class<?> getAnnotationClass() {
189			return EnableAutoConfiguration.class;
190		}
191	
192		/**
193		 * Return the auto-configuration class names that should be considered. By default,
194		 * this method will load candidates using {@link ImportCandidates}.
195		 * @param metadata the source metadata
196		 * @param attributes the {@link #getAttributes(AnnotationMetadata) annotation
197		 * attributes}
198		 * @return a list of candidate configurations
199		 */
200		protected List<String> getCandidateConfigurations(AnnotationMetadata metadata,
201				@Nullable AnnotationAttributes attributes) {
202			ImportCandidates importCandidates = ImportCandidates.load(this.autoConfigurationAnnotation,
203					getBeanClassLoader());
204			List<String> configurations = importCandidates.getCandidates();
205			Assert.state(!CollectionUtils.isEmpty(configurations),
206					"No auto configuration classes found in " + "META-INF/spring/"
207							+ this.autoConfigurationAnnotation.getName() + ".imports. If you "
208							+ "are using a custom packaging, make sure that file is correct.");
209			return configurations;
210		}
211	
212		private void checkExcludedClasses(List<String> configurations, Set<String> exclusions) {
213			List<String> invalidExcludes = new ArrayList<>(exclusions.size());
214			ClassLoader classLoader = (this.beanClassLoader != null) ? this.beanClassLoader : getClass().getClassLoader();
215			for (String exclusion : exclusions) {
216				if (ClassUtils.isPresent(exclusion, classLoader) && !configurations.contains(exclusion)) {
217					invalidExcludes.add(exclusion);
218				}
219			}
220			if (!invalidExcludes.isEmpty()) {
221				handleInvalidExcludes(invalidExcludes);
222			}
223		}
224	
225		/**
226		 * Handle any invalid excludes that have been specified.
227		 * @param invalidExcludes the list of invalid excludes (will always have at least one
228		 * element)
229		 */
230		protected void handleInvalidExcludes(List<String> invalidExcludes) {
231			StringBuilder message = new StringBuilder();
232			for (String exclude : invalidExcludes) {
233				message.append("\t- ").append(exclude).append(String.format("%n"));
234			}
235			throw new IllegalStateException(String.format(
236					"The following classes could not be excluded because they are not auto-configuration classes:%n%s",
237					message));
238		}
239	
240		/**
241		 * Return any exclusions that limit the candidate configurations.
242		 * @param metadata the source metadata
243		 * @param attributes the {@link #getAttributes(AnnotationMetadata) annotation
244		 * attributes}
245		 * @return exclusions or an empty set
246		 */
247		protected Set<String> getExclusions(AnnotationMetadata metadata, @Nullable AnnotationAttributes attributes) {
248			Set<String> excluded = new LinkedHashSet<>();
249			if (attributes != null) {
250				excluded.addAll(asList(attributes, "exclude"));
251				excluded.addAll(asList(attributes, "excludeName"));
252			}
253			excluded.addAll(getExcludeAutoConfigurationsProperty());
254			return getAutoConfigurationReplacements().replaceAll(excluded);
255		}
256	
257		/**
258		 * Returns the auto-configurations excluded by the
259		 * {@code spring.autoconfigure.exclude} property.
260		 * @return excluded auto-configurations
261		 * @since 2.3.2
262		 */
263		protected List<String> getExcludeAutoConfigurationsProperty() {
264			Environment environment = getEnvironment();
265			if (environment == null) {
266				return Collections.emptyList();
267			}
268			if (environment instanceof ConfigurableEnvironment) {
269				Binder binder = Binder.get(environment);
270				return binder.bind(PROPERTY_NAME_AUTOCONFIGURE_EXCLUDE, String[].class)
271					.map(Arrays::asList)
272					.orElse(Collections.emptyList());
273			}
274			String[] excludes = environment.getProperty(PROPERTY_NAME_AUTOCONFIGURE_EXCLUDE, String[].class);
275			return (excludes != null) ? Arrays.asList(excludes) : Collections.emptyList();
276		}
277	
278		protected List<AutoConfigurationImportFilter> getAutoConfigurationImportFilters() {
279			return SpringFactoriesLoader.loadFactories(AutoConfigurationImportFilter.class, this.beanClassLoader);
280		}
281	
282		private ConfigurationClassFilter getConfigurationClassFilter() {
283			ConfigurationClassFilter configurationClassFilter = this.configurationClassFilter;
284			if (configurationClassFilter == null) {
285				List<AutoConfigurationImportFilter> filters = getAutoConfigurationImportFilters();
286				for (AutoConfigurationImportFilter filter : filters) {
287					invokeAwareMethods(filter);
288				}
289				configurationClassFilter = new ConfigurationClassFilter(this.beanClassLoader, filters);
290				this.configurationClassFilter = configurationClassFilter;
291			}
292			return configurationClassFilter;
293		}
294	
295		private AutoConfigurationReplacements getAutoConfigurationReplacements() {
296			AutoConfigurationReplacements autoConfigurationReplacements = this.autoConfigurationReplacements;
297			if (autoConfigurationReplacements == null) {
298				autoConfigurationReplacements = AutoConfigurationReplacements.load(this.autoConfigurationAnnotation,
299						this.beanClassLoader);
300				this.autoConfigurationReplacements = autoConfigurationReplacements;
301			}
302			return autoConfigurationReplacements;
303		}
304	
305		protected final <T> List<T> removeDuplicates(List<T> list) {
306			return new ArrayList<>(new LinkedHashSet<>(list));
307		}
308	
309		protected final List<String> asList(AnnotationAttributes attributes, String name) {
310			String[] value = attributes.getStringArray(name);
311			return Arrays.asList(value);
312		}
313	
314		private void fireAutoConfigurationImportEvents(List<String> configurations, Set<String> exclusions) {
315			List<AutoConfigurationImportListener> listeners = getAutoConfigurationImportListeners();
316			if (!listeners.isEmpty()) {
317				AutoConfigurationImportEvent event = new AutoConfigurationImportEvent(this, configurations, exclusions);
318				for (AutoConfigurationImportListener listener : listeners) {
319					invokeAwareMethods(listener);
320					listener.onAutoConfigurationImportEvent(event);
321				}
322			}
323		}
324	
325		protected List<AutoConfigurationImportListener> getAutoConfigurationImportListeners() {
326			return SpringFactoriesLoader.loadFactories(AutoConfigurationImportListener.class, this.beanClassLoader);
327		}
328	
329		private void invokeAwareMethods(Object instance) {
330			if (instance instanceof Aware) {
331				if (instance instanceof BeanClassLoaderAware beanClassLoaderAwareInstance) {
332					beanClassLoaderAwareInstance.setBeanClassLoader(this.beanClassLoader);
333				}
334				if (instance instanceof BeanFactoryAware beanFactoryAwareInstance) {
335					beanFactoryAwareInstance.setBeanFactory(this.beanFactory);
336				}
337				if (instance instanceof EnvironmentAware environmentAwareInstance) {
338					environmentAwareInstance.setEnvironment(this.environment);
339				}
340				if (instance instanceof ResourceLoaderAware resourceLoaderAwareInstance) {
341					resourceLoaderAwareInstance.setResourceLoader(this.resourceLoader);
342				}
343			}
344		}
345	
346		@Override
347		public void setBeanFactory(BeanFactory beanFactory) throws BeansException {
348			Assert.isInstanceOf(ConfigurableListableBeanFactory.class, beanFactory);
349			this.beanFactory = (ConfigurableListableBeanFactory) beanFactory;
350		}
351	
352		protected final ConfigurableListableBeanFactory getBeanFactory() {
353			return this.beanFactory;
354		}
355	
356		@Override
357		public void setBeanClassLoader(ClassLoader classLoader) {
358			this.beanClassLoader = classLoader;
359		}
360	
361		protected ClassLoader getBeanClassLoader() {
362			return this.beanClassLoader;
363		}
364	
365		@Override
366		public void setEnvironment(Environment environment) {
367			this.environment = environment;
368		}
369	
370		protected final Environment getEnvironment() {
371			return this.environment;
372		}
373	
374		@Override
375		public void setResourceLoader(ResourceLoader resourceLoader) {
376			this.resourceLoader = resourceLoader;
377		}
378	
379		protected final ResourceLoader getResourceLoader() {
380			return this.resourceLoader;
381		}
382	
383		@Override
384		public int getOrder() {
385			return ORDER;
386		}
387	
388		private static class ConfigurationClassFilter {
389	
390			private final AutoConfigurationMetadata autoConfigurationMetadata;
391	
392			private final List<AutoConfigurationImportFilter> filters;
393	
394			ConfigurationClassFilter(ClassLoader classLoader, List<AutoConfigurationImportFilter> filters) {
395				this.autoConfigurationMetadata = AutoConfigurationMetadataLoader.loadMetadata(classLoader);
396				this.filters = filters;
397			}
398	
399			List<String> filter(List<String> configurations) {
400				long startTime = System.nanoTime();
401				@Nullable String[] candidates = StringUtils.toStringArray(configurations);
402				boolean skipped = false;
403				for (AutoConfigurationImportFilter filter : this.filters) {
404					boolean[] match = filter.match(candidates, this.autoConfigurationMetadata);
405					for (int i = 0; i < match.length; i++) {
406						if (!match[i]) {
407							candidates[i] = null;
408							skipped = true;
409						}
410					}
411				}
412				if (!skipped) {
413					return configurations;
414				}
415				List<String> result = new ArrayList<>(candidates.length);
416				for (String candidate : candidates) {
417					if (candidate != null) {
418						result.add(candidate);
419					}
420				}
421				if (logger.isTraceEnabled()) {
422					int numberFiltered = configurations.size() - result.size();
423					logger.trace("Filtered " + numberFiltered + " auto configuration class in "
424							+ TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime) + " ms");
425				}
426				return result;
427			}
428	
429		}
430	
431		private static final class AutoConfigurationGroup
432				implements DeferredImportSelector.Group, BeanClassLoaderAware, BeanFactoryAware, ResourceLoaderAware {
433	
434			private final Map<String, AnnotationMetadata> entries = new LinkedHashMap<>();
435	
436			private final List<AutoConfigurationEntry> autoConfigurationEntries = new ArrayList<>();
437	
438			@SuppressWarnings("NullAway.Init")
439			private ClassLoader beanClassLoader;
440	
441			@SuppressWarnings("NullAway.Init")
442			private BeanFactory beanFactory;
443	
444			@SuppressWarnings("NullAway.Init")
445			private ResourceLoader resourceLoader;
446	
447			private @Nullable AutoConfigurationMetadata autoConfigurationMetadata;
448	
449			private @Nullable AutoConfigurationReplacements autoConfigurationReplacements;
450	
451			@Override
452			public void setBeanClassLoader(ClassLoader classLoader) {
453				this.beanClassLoader = classLoader;
454			}
455	
456			@Override
457			public void setBeanFactory(BeanFactory beanFactory) {
458				this.beanFactory = beanFactory;
459			}
460	
461			@Override
462			public void setResourceLoader(ResourceLoader resourceLoader) {
463				this.resourceLoader = resourceLoader;
464			}
465	
466			@Override
467			public void process(AnnotationMetadata annotationMetadata, DeferredImportSelector deferredImportSelector) {
468				Assert.state(deferredImportSelector instanceof AutoConfigurationImportSelector,
469						() -> String.format("Only %s implementations are supported, got %s",
470								AutoConfigurationImportSelector.class.getSimpleName(),
471								deferredImportSelector.getClass().getName()));
472				AutoConfigurationImportSelector autoConfigurationImportSelector = (AutoConfigurationImportSelector) deferredImportSelector;
473				AutoConfigurationReplacements autoConfigurationReplacements = autoConfigurationImportSelector
474					.getAutoConfigurationReplacements();
475				Assert.state(
476						this.autoConfigurationReplacements == null
477								|| this.autoConfigurationReplacements.equals(autoConfigurationReplacements),
478						"Auto-configuration replacements must be the same for each call to process");
479				this.autoConfigurationReplacements = autoConfigurationReplacements;
480				AutoConfigurationEntry autoConfigurationEntry = autoConfigurationImportSelector
481					.getAutoConfigurationEntry(annotationMetadata);
482				this.autoConfigurationEntries.add(autoConfigurationEntry);
483				for (String importClassName : autoConfigurationEntry.getConfigurations()) {
484					this.entries.putIfAbsent(importClassName, annotationMetadata);
485				}
486			}
487	
488			@Override
489			public Iterable<Entry> selectImports() {
490				if (this.autoConfigurationEntries.isEmpty()) {
491					return Collections.emptyList();
492				}
493				Set<String> allExclusions = this.autoConfigurationEntries.stream()
494					.map(AutoConfigurationEntry::getExclusions)
495					.flatMap(Collection::stream)
496					.collect(Collectors.toSet());
497				Set<String> processedConfigurations = this.autoConfigurationEntries.stream()
498					.map(AutoConfigurationEntry::getConfigurations)
499					.flatMap(Collection::stream)
500					.collect(Collectors.toCollection(LinkedHashSet::new));
501				processedConfigurations.removeAll(allExclusions);
502				return sortAutoConfigurations(processedConfigurations, getAutoConfigurationMetadata()).stream()
503					.map(this::getEntry)
504					.toList();
505			}
506	
507			private Entry getEntry(String importClassName) {
508				AnnotationMetadata metadata = this.entries.get(importClassName);
509				Assert.state(metadata != null, "'metadata' must not be null");
510				return new Entry(metadata, importClassName);
511			}
512	
513			private AutoConfigurationMetadata getAutoConfigurationMetadata() {
514				if (this.autoConfigurationMetadata == null) {
515					this.autoConfigurationMetadata = AutoConfigurationMetadataLoader.loadMetadata(this.beanClassLoader);
516				}
517				return this.autoConfigurationMetadata;
518			}
519	
520			private List<String> sortAutoConfigurations(Set<String> configurations,
521					AutoConfigurationMetadata autoConfigurationMetadata) {
522				Assert.state(this.autoConfigurationReplacements != null,
523						"'autoConfigurationReplacements' must not be null");
524				return new AutoConfigurationSorter(getMetadataReaderFactory(), autoConfigurationMetadata,
525						this.autoConfigurationReplacements::replace)
526					.getInPriorityOrder(configurations);
527			}
528	
529			private MetadataReaderFactory getMetadataReaderFactory() {
530				try {
531					return this.beanFactory.getBean(SharedMetadataReaderFactoryContextInitializer.BEAN_NAME,
532							MetadataReaderFactory.class);
533				}
534				catch (NoSuchBeanDefinitionException ex) {
535					return new CachingMetadataReaderFactory(this.resourceLoader);
536				}
537			}
538	
539		}
540	
541		protected static class AutoConfigurationEntry {
542	
543			private final List<String> configurations;
544	
545			private final Set<String> exclusions;
546	
547			private AutoConfigurationEntry() {
548				this.configurations = Collections.emptyList();
549				this.exclusions = Collections.emptySet();
550			}
551	
552			/**
553			 * Create an entry with the configurations that were contributed and their
554			 * exclusions.
555			 * @param configurations the configurations that should be imported
556			 * @param exclusions the exclusions that were applied to the original list
557			 */
558			AutoConfigurationEntry(Collection<String> configurations, Collection<String> exclusions) {
559				this.configurations = new ArrayList<>(configurations);
560				this.exclusions = new HashSet<>(exclusions);
561			}
562	
563			public List<String> getConfigurations() {
564				return this.configurations;
565			}
566	
567			public Set<String> getExclusions() {
568				return this.exclusions;
569			}
570	
571		}
572	
573	}
