36	/**
37	 * Abstract base class for a {@link SpringBootCondition} that also implements
38	 * {@link AutoConfigurationImportFilter}.
39	 *
40	 * @author Phillip Webb
41	 */
42	abstract class FilteringSpringBootCondition extends SpringBootCondition
43			implements AutoConfigurationImportFilter, BeanFactoryAware, BeanClassLoaderAware {
44	
45		@SuppressWarnings("NullAway.Init")
46		private BeanFactory beanFactory;
47	
48		@SuppressWarnings("NullAway.Init")
49		private ClassLoader beanClassLoader;
50	
51		@Override
52		public boolean[] match(@Nullable String[] autoConfigurationClasses,
53				AutoConfigurationMetadata autoConfigurationMetadata) {
54			ConditionEvaluationReport report = ConditionEvaluationReport.find(this.beanFactory);
55			@Nullable ConditionOutcome[] outcomes = getOutcomes(autoConfigurationClasses, autoConfigurationMetadata);
56			boolean[] match = new boolean[outcomes.length];
57			for (int i = 0; i < outcomes.length; i++) {
58				ConditionOutcome outcome = outcomes[i];
59				match[i] = (outcome == null || outcome.isMatch());
60				if (!match[i] && outcome != null) {
61					String autoConfigurationClass = autoConfigurationClasses[i];
62					Assert.state(autoConfigurationClass != null, "'autoConfigurationClass' must not be null");
63					logOutcome(autoConfigurationClass, outcome);
64					if (report != null) {
65						report.recordConditionEvaluation(autoConfigurationClass, this, outcome);
66					}
67				}
68			}
69			return match;
70		}
71	
72		protected abstract @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses,
73				AutoConfigurationMetadata autoConfigurationMetadata);
74	
75		@Override
76		public void setBeanFactory(BeanFactory beanFactory) throws BeansException {
77			this.beanFactory = beanFactory;
78		}
79	
80		protected final BeanFactory getBeanFactory() {
81			return this.beanFactory;
82		}
83	
84		protected final ClassLoader getBeanClassLoader() {
85			return this.beanClassLoader;
86		}
87	
88		@Override
89		public void setBeanClassLoader(ClassLoader classLoader) {
90			this.beanClassLoader = classLoader;
91		}
92	
93		protected final List<String> filter(@Nullable Collection<String> classNames, ClassNameFilter classNameFilter,
94				@Nullable ClassLoader classLoader) {
95			if (CollectionUtils.isEmpty(classNames)) {
96				return Collections.emptyList();
97			}
98			List<String> matches = new ArrayList<>(classNames.size());
99			for (String candidate : classNames) {
100				if (classNameFilter.matches(candidate, classLoader)) {
101					matches.add(candidate);
102				}
103			}
104			return matches;
105		}
106	
107		/**
108		 * Slightly faster variant of {@link ClassUtils#forName(String, ClassLoader)} that
109		 * doesn't deal with primitives, arrays or inner types.
110		 * @param className the class name to resolve
111		 * @param classLoader the class loader to use
112		 * @return a resolved class
113		 * @throws ClassNotFoundException if the class cannot be found
114		 */
115		protected static Class<?> resolve(String className, @Nullable ClassLoader classLoader)
116				throws ClassNotFoundException {
117			if (classLoader != null) {
118				return Class.forName(className, false, classLoader);
119			}
120			return Class.forName(className);
121		}
122	
123		protected enum ClassNameFilter {
124	
125			PRESENT {
126	
127				@Override
128				public boolean matches(String className, @Nullable ClassLoader classLoader) {
129					return isPresent(className, classLoader);
130				}
131	
132			},
133	
134			MISSING {
135	
136				@Override
137				public boolean matches(String className, @Nullable ClassLoader classLoader) {
138					return !isPresent(className, classLoader);
139				}
140	
141			};
142	
143			abstract boolean matches(String className, @Nullable ClassLoader classLoader);
144	
145			private static boolean isPresent(String className, @Nullable ClassLoader classLoader) {
146				if (classLoader == null) {
147					classLoader = ClassUtils.getDefaultClassLoader();
148				}
149				try {
150					resolve(className, classLoader);
151					return true;
152				}
153				catch (Throwable ex) {
154					return false;
155				}
156			}
157	
158		}
159	
160	}
