14	 * limitations under the License.
15	 */
16	
17	package org.springframework.boot.autoconfigure;
18	
19	import java.io.IOException;
20	import java.lang.annotation.Annotation;
21	import java.util.ArrayList;
22	import java.util.Collection;
23	import java.util.Collections;
24	import java.util.Comparator;
25	import java.util.LinkedHashMap;
26	import java.util.LinkedHashSet;
27	import java.util.List;
28	import java.util.Map;
29	import java.util.Set;
30	import java.util.TreeSet;
31	import java.util.function.UnaryOperator;
32	
33	import org.jspecify.annotations.Nullable;
34	
35	import org.springframework.core.type.AnnotationMetadata;
36	import org.springframework.core.type.classreading.MetadataReader;
37	import org.springframework.core.type.classreading.MetadataReaderFactory;
38	import org.springframework.util.Assert;
39	
40	/**
41	 * Sort {@link EnableAutoConfiguration auto-configuration} classes into priority order by
42	 * reading {@link AutoConfigureOrder @AutoConfigureOrder},
43	 * {@link AutoConfigureBefore @AutoConfigureBefore} and
44	 * {@link AutoConfigureAfter @AutoConfigureAfter} annotations (without loading classes).
45	 *
46	 * @author Phillip Webb
47	 */
48	class AutoConfigurationSorter {
49	
50		private final MetadataReaderFactory metadataReaderFactory;
51	
52		private final @Nullable AutoConfigurationMetadata autoConfigurationMetadata;
53	
54		private final @Nullable UnaryOperator<String> replacementMapper;
55	
56		AutoConfigurationSorter(MetadataReaderFactory metadataReaderFactory,
57				@Nullable AutoConfigurationMetadata autoConfigurationMetadata,
58				@Nullable UnaryOperator<String> replacementMapper) {
59			Assert.notNull(metadataReaderFactory, "'metadataReaderFactory' must not be null");
60			this.metadataReaderFactory = metadataReaderFactory;
61			this.autoConfigurationMetadata = autoConfigurationMetadata;
62			this.replacementMapper = replacementMapper;
63		}
64	
65		List<String> getInPriorityOrder(Collection<String> classNames) {
66			// Initially sort alphabetically
67			List<String> alphabeticallyOrderedClassNames = new ArrayList<>(classNames);
68			Collections.sort(alphabeticallyOrderedClassNames);
69			// Then sort by order
70			AutoConfigurationClasses classes = new AutoConfigurationClasses(this.metadataReaderFactory,
71					this.autoConfigurationMetadata, alphabeticallyOrderedClassNames);
72			List<String> orderedClassNames = new ArrayList<>(classNames);
73			Collections.sort(orderedClassNames);
74			orderedClassNames.sort((o1, o2) -> {
75				int i1 = classes.get(o1).getOrder();
76				int i2 = classes.get(o2).getOrder();
77				return Integer.compare(i1, i2);
78			});
79			// Then respect @AutoConfigureBefore @AutoConfigureAfter
80			orderedClassNames = sortByAnnotation(classes, orderedClassNames);
81			return orderedClassNames;
82		}
83	
84		private List<String> sortByAnnotation(AutoConfigurationClasses classes, List<String> classNames) {
85			List<String> toSort = new ArrayList<>(classNames);
86			toSort.addAll(classes.getAllNames());
87			Set<String> sorted = new LinkedHashSet<>();
88			Set<String> processing = new LinkedHashSet<>();
89			while (!toSort.isEmpty()) {
90				doSortByAfterAnnotation(classes, toSort, sorted, processing, null);
91			}
92			sorted.retainAll(classNames);
93			return new ArrayList<>(sorted);
94		}
95	
96		private void doSortByAfterAnnotation(AutoConfigurationClasses classes, List<String> toSort, Set<String> sorted,
97				Set<String> processing, @Nullable String current) {
98			if (current == null) {
99				current = toSort.remove(0);
100			}
101			processing.add(current);
102			Set<String> afters = new TreeSet<>(Comparator.comparing(toSort::indexOf));
103			afters.addAll(classes.getClassesRequestedAfter(current));
104			for (String after : afters) {
105				checkForCycles(processing, current, after);
106				if (!sorted.contains(after) && toSort.contains(after)) {
107					doSortByAfterAnnotation(classes, toSort, sorted, processing, after);
108				}
109			}
110			processing.remove(current);
111			sorted.add(current);
112		}
113	
114		private void checkForCycles(Set<String> processing, String current, String after) {
115			Assert.state(!processing.contains(after),
116					() -> "AutoConfigure cycle detected between " + current + " and " + after);
117		}
118	
119		private class AutoConfigurationClasses {
120	
121			private final Map<String, AutoConfigurationClass> classes = new LinkedHashMap<>();
122	
123			AutoConfigurationClasses(MetadataReaderFactory metadataReaderFactory,
124					@Nullable AutoConfigurationMetadata autoConfigurationMetadata, Collection<String> classNames) {
125				addToClasses(metadataReaderFactory, autoConfigurationMetadata, classNames, true);
126			}
127	
128			Set<String> getAllNames() {
129				return this.classes.keySet();
130			}
131	
132			private void addToClasses(MetadataReaderFactory metadataReaderFactory,
133					@Nullable AutoConfigurationMetadata autoConfigurationMetadata, Collection<String> classNames,
134					boolean required) {
135				for (String className : classNames) {
136					if (!this.classes.containsKey(className)) {
137						AutoConfigurationClass autoConfigurationClass = new AutoConfigurationClass(className,
138								metadataReaderFactory, autoConfigurationMetadata);
139						boolean available = autoConfigurationClass.isAvailable();
140						if (required || available) {
141							this.classes.put(className, autoConfigurationClass);
142						}
143						if (available) {
144							addToClasses(metadataReaderFactory, autoConfigurationMetadata,
145									autoConfigurationClass.getBefore(), false);
146							addToClasses(metadataReaderFactory, autoConfigurationMetadata,
147									autoConfigurationClass.getAfter(), false);
148						}
149					}
150				}
151			}
152	
153			AutoConfigurationClass get(String className) {
154				AutoConfigurationClass autoConfigurationClass = this.classes.get(className);
155				Assert.state(autoConfigurationClass != null, "'autoConfigurationClass' must not be null");
156				return autoConfigurationClass;
157			}
158	
159			Set<String> getClassesRequestedAfter(String className) {
160				Set<String> classesRequestedAfter = new LinkedHashSet<>(get(className).getAfter());
161				this.classes.forEach((name, autoConfigurationClass) -> {
162					if (autoConfigurationClass.getBefore().contains(className)) {
163						classesRequestedAfter.add(name);
164					}
165				});
166				return classesRequestedAfter;
167			}
168	
169		}
170	
171		private class AutoConfigurationClass {
172	
173			private final String className;
174	
175			private final MetadataReaderFactory metadataReaderFactory;
176	
177			private final @Nullable AutoConfigurationMetadata autoConfigurationMetadata;
178	
179			private volatile @Nullable AnnotationMetadata annotationMetadata;
180	
181			private volatile @Nullable Set<String> before;
182	
183			private volatile @Nullable Set<String> after;
184	
185			AutoConfigurationClass(String className, MetadataReaderFactory metadataReaderFactory,
186					@Nullable AutoConfigurationMetadata autoConfigurationMetadata) {
187				this.className = className;
188				this.metadataReaderFactory = metadataReaderFactory;
189				this.autoConfigurationMetadata = autoConfigurationMetadata;
190			}
191	
192			boolean isAvailable() {
193				try {
194					if (!wasProcessed()) {
195						getAnnotationMetadata();
196					}
197					return true;
198				}
199				catch (Exception ex) {
200					return false;
201				}
202			}
203	
204			Set<String> getBefore() {
205				Set<String> before = this.before;
206				if (before == null) {
207					before = getClassNames("AutoConfigureBefore", AutoConfigureBefore.class);
208					this.before = before;
209				}
210				return before;
211			}
212	
213			Set<String> getAfter() {
214				Set<String> after = this.after;
215				if (after == null) {
216					after = getClassNames("AutoConfigureAfter", AutoConfigureAfter.class);
217					this.after = after;
218				}
219				return after;
220			}
221	
222			private Set<String> getClassNames(String metadataKey, Class<? extends Annotation> annotation) {
223				Set<String> annotationValue = wasProcessed() ? getSet(metadataKey) : getAnnotationValue(annotation);
224				return applyReplacements(annotationValue);
225			}
226	
227			private Set<String> getSet(String metadataKey) {
228				Assert.state(this.autoConfigurationMetadata != null, "'autoConfigurationMetadata' must not be null");
229				return this.autoConfigurationMetadata.getSet(this.className, metadataKey, Collections.emptySet());
230			}
231	
232			private Set<String> applyReplacements(Set<String> values) {
233				if (AutoConfigurationSorter.this.replacementMapper == null) {
234					return values;
235				}
236				Set<String> replaced = new LinkedHashSet<>(values);
237				for (String value : values) {
238					replaced.add(AutoConfigurationSorter.this.replacementMapper.apply(value));
239				}
240				return replaced;
241			}
242	
243			private int getOrder() {
244				if (wasProcessed()) {
245					Assert.state(this.autoConfigurationMetadata != null, "'autoConfigurationMetadata' must not be null");
246					return this.autoConfigurationMetadata.getInteger(this.className, "AutoConfigureOrder",
247							AutoConfigureOrder.DEFAULT_ORDER);
248				}
249				Map<String, @Nullable Object> attributes = getAnnotationMetadata()
250					.getAnnotationAttributes(AutoConfigureOrder.class.getName());
251				if (attributes != null) {
252					Integer value = (Integer) attributes.get("value");
253					Assert.state(value != null, "'value' must not be null");
254					return value;
255				}
256				return AutoConfigureOrder.DEFAULT_ORDER;
257			}
258	
259			private boolean wasProcessed() {
260				return (this.autoConfigurationMetadata != null
261						&& this.autoConfigurationMetadata.wasProcessed(this.className));
262			}
263	
264			private Set<String> getAnnotationValue(Class<?> annotation) {
265				Map<String, @Nullable Object> attributes = getAnnotationMetadata()
266					.getAnnotationAttributes(annotation.getName(), true);
267				if (attributes == null) {
268					return Collections.emptySet();
269				}
270				Set<String> result = new LinkedHashSet<>();
271				String[] value = (String[]) attributes.get("value");
272				String[] name = (String[]) attributes.get("name");
273				Assert.state(value != null, "'value' must not be null");
274				Assert.state(name != null, "'name' must not be null");
275				Collections.addAll(result, value);
276				Collections.addAll(result, name);
277				return result;
278			}
279	
280			private AnnotationMetadata getAnnotationMetadata() {
281				AnnotationMetadata annotationMetadata = this.annotationMetadata;
282				if (annotationMetadata == null) {
283					try {
284						MetadataReader metadataReader = this.metadataReaderFactory.getMetadataReader(this.className);
285						annotationMetadata = metadataReader.getAnnotationMetadata();
286						this.annotationMetadata = annotationMetadata;
287					}
288					catch (IOException ex) {
289						throw new IllegalStateException("Unable to read meta-data for class " + this.className, ex);
290					}
291				}
292				return annotationMetadata;
293			}
294	
295		}
296	
